            "data": [
                {
                    "name": "Edge-Templates",
                    "type": "tmplgrp",
                    "template group setting": {
                        "cliprofs": [
                            "Edge-Template"
                        ],
                        "templates": [
                            "5__Edge",
                            "4-2__Default-Route"
                        ]
                    },
                    "scope member": [
                        {
                            "is group": 1,
                            "name": "Edge"
                        }
                    ]
                },
                {
                    "name": "Hub-Templates",
                    "type": "tmplgrp",
                    "template group setting": {
                        "cliprofs": [
                            "Hub-Template"
                        ],
                        "templates": [
                            "5__Hub",
                            "4-2__Default-Route"
                        ]
                    },
                    "scope member": [
                        {
                            "is group": 1,
                            "name": "Hubs"
                        }
                    ]
                }
            ]
        }
    ]
}

